~L1: I think the retry logic has a race condition when multiple workers read and update retry state at the same time.
~L2:
#ctx {cmp:"retry-flow" risk:"race"}
^lk:retry_state
^if {$retry.inflight:true} <<
  !mod @mem {k:"retry.queue" op:"append" v:$req.id}
  ^ulk:retry_state
  ^rt {st:skp why:"already_inflight"}
>>
!mod @mem {k:"retry.inflight" v:true}
!mod @mem {k:"retry.attempt" op:"inc" v:1}
^ulk:retry_state
!run @sh {cmd:"do_retry $req.id"} ->$res
^lk:retry_state
!mod @mem {k:"retry.inflight" v:false}
^if {$res.st:fl} {!mod @mem {k:"retry.queue" op:"append" v:$req.id}}
^ulk:retry_state
>ok {fix:"mutex lock around retry state read/write"}

